// 二分查找码位 -> glyph; 未命中返回 NULL
static inline const uint16_t* cjk16_lookup(uint32_t cp) {
    int lo = 0, hi = CJK16_COUNT - 1;
    while (lo <= hi) {
        int mid = (lo + hi) >> 1;
        uint32_t v = cjk16_codepoints[mid];
        if (v == cp) return cjk16_glyphs[mid];
        if (v < cp) lo = mid + 1; else hi = mid - 1;
    }
    return 0;
}

