// 码位 -> ascii glyph; 越界返回 NULL
static inline const uint8_t* ascii16_lookup(uint32_t cp) {
    if (cp < ASCII16_FIRST || cp > ASCII16_LAST) return 0;
    return ascii16_glyphs[cp - ASCII16_FIRST];
}

